parameters.jsCode:
const raw = $input.first().json;
const agentOutput = raw.output || raw.text || raw;

let parsedData;
try {
  const text = typeof agentOutput === 'string' ? agentOutput : JSON.stringify(agentOutput);
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  parsedData = jsonMatch ? JSON.parse(jsonMatch[0]) : { raw: agentOutput };
} catch (e) {
  parsedData = { parse_error: e.message, raw: agentOutput };
}

// Ordenar resultados por relevance_score descendente
if (parsedData.results && Array.isArray(parsedData.results)) {
  parsedData.results.sort((a, b) => (b.relevance_score || 0) - (a.relevance_score || 0));
}

return {
  success: true,
  timestamp: new Date().toISOString(),
  source: 'RenderHub-3D-Brain-v1',
  ...parsedData
};
